115→    public static function fetchSpecialConfig(string $type): array
116→    {
117→        $data = redis()->hget(self::RK_DATA, $type);
118→        if (!$data) {
119→            /** @var WorkflowSpecialStakeholder $query */
120→            $query = WorkflowSpecialStakeholder::where('type', $type)->first();
121→            if ($query != null) {
122→                $data = [
123→                    'ids' => $query->ids,
124→                    'config' => $query->special_config,
125→                ];
126→                $data = my_json_encode($data);
127→                redis()->hset(self::RK_DATA, $type, $data);
128→            } else {
129→                throw new WorkflowException("Special stakeholder type {$type} Not Found");
130→            }
131→        }
132→        return my_json_decode($data);
133→    }
