135→    /**
136→     * 获取特殊花名的 sfuser id。
137→     *
138→     * @param string $type
139→     * @param int $sfuserId
140→     * @param array $context
141→     * @param bool $throwException
142→     * @throws Exception
143→     * @return mixed
144→     */
145→    public static function fetchSpecialSfuserId(string $type, int $sfuserId, array $context, bool $throwException = true)
146→    {
147→        $data = redis()->hget(self::RK_DATA, $type);
148→        if (!$data) {
149→            // 如果 redis 中不存在数据，首先从 DB 中 fetch
150→            /** @var WorkflowSpecialStakeholder $query */
151→            $query = WorkflowSpecialStakeholder::where('type', $type)->first();
152→            if ($query != null) {
153→                // automatically cast to array
154→                $data = [
155→                    'ids' => $query->ids,
156→                    'config' => $query->special_config,
157→                ];
158→                $data = my_json_encode($data);
159→                redis()->hset(self::RK_DATA, $type, $data);
160→            } else {
161→                // TODO-MSG: 类型为 :type 的特殊审批人尚未配置，请联系管理员
162→                throw new WorkflowException("Special stakeholder type {$type} Not Found");
163→            }
164→        }
165→
166→        $configItems = my_json_decode($data);
167→
168→        // 默认采用外面的 ids
169→        $ids = $configItems['ids'];
170→        $config = $configItems['config'];
171→        if ($config) {
172→            // 存在特殊配置，需要根据当前人的属性进行查找
173→            if ($type == WorkflowRequestStakeholder::P4V_SUPERVISOR_TYPE) {
174→                foreach ($config as $subConfig) {
175→                    if ($context['target_department'] == $subConfig['p4v_department_id']) {
176→                        $ids = $subConfig['ids'];
177→                        break;
178→                    }
179→                }
180→            } elseif ($type == WorkflowRequestStakeholder::P4V_EXECUTER_TYPE) {
181→                $ids = self::getP4vExecute($config, $context, $ids);
182→            } elseif ($type == WorkflowRequestStakeholder::TEAM_DEPT_TYPE) {
183→                foreach ($config as $subConfig) {
184→                    if ($context['team_department'] == $subConfig['team_department']) {
185→                        $ids = [$subConfig['team_sfuser_id']];
186→                        break;
187→                    }
188→                }
189→            } else {
190→                /** @var Sfuser $sfuser */
191→                $sfuser = Sfuser::findOrFail($sfuserId);
192→                // 部门不能重叠，这一点需要在新增或编辑时进行判断。
193→                foreach ($config as $subConfig) {
194→                    $departmentIds = Arr::get($subConfig, 'department_ids', []);
195→                    if (in_array($sfuser->department_id, $departmentIds)) {
196→                        // 命中了，使用命中的自定义规则
197→                        $ids = $subConfig['ids'];
198→                        break; // 退出循环
199→                    }
200→                }
201→            }
202→        }
203→        // ddd
204→        if ($type == WorkflowRequestStakeholder::REIMBURSEMENT_TEST_EXPAT_SUPERVISOR_TYPE) {
205→            if (array_key_exists('branch', $context)) {
206→                $r = ReimbursementCostSubject::where('id', $context['branch'])->first();
207→                if ($r) {
208→                    if ($r->parent_id === 6) {
209→                        $wr = WorkflowSpecialStakeholder::where(
210→                            'type',
211→                            WorkflowRequestStakeholder::REIMBURSEMENT_TEST_EXPAT_SUPERVISOR_CHIEF_ALMIGHTY_TYPE
212→                        )->first();
213→                        if ($wr) {
214→                            $ids = $wr->ids;
215→                        } else {
216→                            throw new WorkflowException('请联系管理员配置【测试外派打车费审批人员-大酋长】后再操作');
217→                        }
218→                    }
219→                    if ($r->parent_id === 7) {
220→                        $wr = WorkflowSpecialStakeholder::where(
221→                            'type',
222→                            WorkflowRequestStakeholder::REIMBURSEMENT_TEST_EXPAT_SUPERVISOR_MAFIA_CITY_2_TYPE
223→                        )->first();
224→                        if ($wr) {
225→                            $ids = $wr->ids;
226→                        } else {
227→                            throw new WorkflowException('请联系管理员配置【测试外派打车费审批人员-大黑帮】后再操作');
228→                        }
229→                    }
230→                }
231→            }
232→            if (array_key_exists('department', $context)) {
233→                if ($context['department'] === 16) {
234→                    $wr = WorkflowSpecialStakeholder::where(
235→                        'type',
236→                        WorkflowRequestStakeholder::REIMBURSEMENT_TEST_EXPAT_SUPERVISOR_HD_TYPE
237→                    )->first();
238→                    if ($wr) {
239→                        $ids = $wr->ids;
240→                    } else {
241→                        throw new WorkflowException('请联系管理员配置【测试外派打车费审批人员-黑道风云】后再操作');
242→                    }
243→                }
244→                if ($context['department'] === 76) {
245→                    $wr = WorkflowSpecialStakeholder::where(
246→                        'type',
247→                        WorkflowRequestStakeholder::REIMBURSEMENT_TEST_EXPAT_SUPERVISOR_D_TYPE
248→                    )->first();
249→                    if ($wr) {
250→                        $ids = $wr->ids;
251→                    } else {
252→                        throw new WorkflowException('请联系管理员配置【测试外派打车费审批人员-Project D】后再操作');
253→                    }
254→                }
255→                if ($context['department'] === 72) {
256→                    $wr = WorkflowSpecialStakeholder::where(
257→                        'type',
258→                        WorkflowRequestStakeholder::REIMBURSEMENT_TEST_EXPAT_SUPERVISOR_X_TYPE
259→                    )->first();
260→                    if ($wr) {
261→                        $ids = $wr->ids;
262→                    } else {
263→                        throw new WorkflowException('请联系管理员配置【测试外派打车费审批人员-Project X】后再操作');
264→                    }
265→                }
266→                if ($context['department'] === 2) {
267→                    $wr = WorkflowSpecialStakeholder::where(
268→                        'type',
269→                        WorkflowRequestStakeholder::REIMBURSEMENT_TEST_EXPAT_SUPERVISOR_ACE_TYPE
270→                    )->first();
271→                    if ($wr) {
272→                        $ids = $wr->ids;
273→                    } else {
274→                        throw new WorkflowException('请联系管理员配置【测试外派打车费审批人员-Ace Alliance】后再操作');
275→                    }
276→                }
277→                if ($context['department'] === 3) {
278→                    $wr = WorkflowSpecialStakeholder::where(
279→                        'type',
280→                        WorkflowRequestStakeholder::REIMBURSEMENT_TEST_EXPAT_SUPERVISOR_HOLLY_TYPE
281→                    )->first();
282→                    if ($wr) {
283→                        $ids = $wr->ids;
284→                    } else {
285→                        throw new WorkflowException('请联系管理员配置【测试外派打车费审批人员-Hollywood Crush】后再操作');
286→                    }
287→                }
288→                if ($context['department'] === 79) {
289→                    $wr = WorkflowSpecialStakeholder::where(
290→                        'type',
291→                        WorkflowRequestStakeholder::REIMBURSEMENT_TEST_EXPAT_SUPERVISOR_P_TYPE
292→                    )->first();
293→                    if ($wr) {
294→                        $ids = $wr->ids;
295→                    } else {
296→                        throw new WorkflowException('请联系管理员配置【测试外派打车费审批人员-Project P】后再操作');
297→                    }
298→                }
299→            }
300→        }
301→
302→        // 如果 ids 为空，不让流程继续流转，直接报错
303→        if (empty($ids) && $throwException) {
304→            // TODO-MSG: 类型为 :type 的特殊审批人尚未配置，请联系管理员
305→            throw new WorkflowException("Special stakeholder type {$type} Not Found");
306→        }
307→
308→        return $ids;
309→    }
