  9→    public const REDIS_CHN_KEY = 'CHN:'.__CLASS__.':IDS';
 10→
 11→    public const REDIS_SGP_KEY = 'SGP:'.__CLASS__.':IDS';
 12→
 13→    public const REDIS_USA_KEY = 'USA:'.__CLASS__.':IDS';
 14→
 15→    public const TTL = 30 * 24 * 3600;
 16→
 17→    public static DepartmentSupervisor|null $instance = null;
 18→
 19→    private mixed $redis;
 20→
 21→    private string $redisKey;
 22→
 23→    private string $redisLockerKey;
 24→
 25→    public function __construct()
 26→    {
 27→        $this->redisKey = config('my_project.site_key').':'.__CLASS__.':IDS';
 28→        $this->redisLockerKey = config('my_project.site_key').':'.__CLASS__.':IDS_LOCKER';
 29→        $this->redis = redis('shared');
 30→    }
 31→
 32→    public static function make(): DepartmentSupervisor
 33→    {
 34→        if (is_null(static::$instance)) {
 35→            static::$instance = new DepartmentSupervisor();
 36→        }
 37→        return static::$instance;
 38→    }
 39→
 40→    /**
 41→     * @throws \RedisException
 42→     * @return false|int|\Redis
 43→     */
 44→    public function clear(): bool|int|\Redis
 45→    {
 46→        return $this->redis->del($this->redisKey);
 47→    }
 48→
 49→    /**
 50→     * 获取部门主管.
 51→     *
 52→     * @return array
 53→     */
 54→    public function getData(string $site = ''): array
 55→    {
 56→        $redisKey = $this->redisKey;
 57→        switch ($site) {
 58→            case 'CHN':
 59→                $redisKey = static::REDIS_CHN_KEY;
 60→                break;
 61→            case 'SGP':
 62→                $redisKey = static::REDIS_SGP_KEY;
 63→                break;
 64→            case 'USA':
 65→                $redisKey = static::REDIS_USA_KEY;
 66→                break;
 67→            case 'all':
 68→                $redisKey = [static::REDIS_CHN_KEY, static::REDIS_SGP_KEY, static::REDIS_USA_KEY];
 69→                // no break
 70→            default:
 71→                break;
 72→        }
 73→        // 各地区 把 sfusers 表的部门主管id 缓存到 redis 里
 74→        if (!$this->redis->exists($redisKey)) {
 75→            $ids = Sfuser::selectRaw('DISTINCT(supervisor_id)')->pluck('supervisor_id')->toArray();
 76→            if (!$this->redis->exists($redisKey)) {
 77→                foreach ($ids as $id) {
 78→                    $this->redis->sAdd($redisKey, $id);
 79→                }
 80→                $this->redis->expire($redisKey, static::TTL); // 30 天过期
 81→            }
 82→        }
 83→        $data = $this->redis->sMembers($redisKey);
 84→        return $data;    // 全部数据
 85→    }
 86→
 87→    // 获取三个地区的全部主管
 88→    public function getAllData()
 89→    {
 90→        $redisKeys = [static::REDIS_CHN_KEY, static::REDIS_SGP_KEY, static::REDIS_USA_KEY];
 91→        $data = [];
 92→        foreach ($redisKeys as $redisKey) {
 93→            if ($this->redis->exists($redisKey)) {
 94→                $data = array_merge($data, $this->redis->sMembers($redisKey));
 95→            }
 96→        }
 97→        return $data;    // 全部数据
 98→    }
 99→
100→    public function isSupervisor(int $sfuserId)
101→    {
102→        $ids = $this->getAllData();
103→        return in_array($sfuserId, $ids);
104→    }
