312→    /**
313→     * 获取特殊花名.
314→     *
315→     * @param string $connection
316→     * @param string $type
317→     * @param array $context
318→     * @return array
319→     */
320→    public function fetchSpecialSfuser(string $connection, string $type, array $context): array
321→    {
322→        // 只有运营, 美术, 市场会有第二第三个部门主管
323→        $departments2 = Arr::only(CommonConst::PAY_STAMP_DEPARTMENT, CommonConst::SECOND_SUPERVISOR_DEPARTMENTS);
324→        $departments3 = Arr::only(CommonConst::PAY_STAMP_DEPARTMENT, CommonConst::THIRD_SUPERVISOR_DEPARTMENTS);
325→        $skip = false;
326→        if ($type == CommonSpecialStakeholder::SECOND_SUPERVISOR_TYPE && !in_array($context['department'], $departments2)
327→            || $type == CommonSpecialStakeholder::THIRD_SUPERVISOR_TYPE && !in_array($context['department'], $departments3)) {
328→            $skip = true;
329→        }
330→
331→        $stakeholders = Stakeholder::getData($connection, $type);
332→        if (empty($stakeholders)) {
333→            if ($skip) {
334→                return ['ids' => [], 'nicknames' => []];
335→            }
336→            throw new WorkflowException("Special stakeholder type {$type} Not Found");
337→        }
338→
339→        // 默认采用外面的 ids
340→        $ids = Arr::get($stakeholders, 'ids', []);
341→        $nicknames = Arr::get($stakeholders, 'nicknames', []);
342→        $config = Arr::get($stakeholders, 'special_config', []);
343→
344→        if ($config) {
345→            // 存在特殊配置
346→            if (in_array($type, CommonSpecialStakeholder::SUPERVISOR_TYPES)) {
347→                foreach ($config as $subConfig) {
348→                    $departmentId = Arr::get($subConfig, 'department_id', 0);
349→                    if ($context['department'] == $departmentId) {
350→                        // 命中了，使用命中的自定义规则
351→                        $ids = $subConfig['ids'];
352→                        $nicknames = $subConfig['nicknames'];
353→                        break; // 使用第一个
354→                    }
355→                }
356→            } elseif (in_array($type, [CommonSpecialStakeholder::STAMP_HANDEL_TYPE, CommonSpecialStakeholder::STAMP_EXECUTE_TYPE])) {
357→                $subIds = [];
358→                $subNicknames = [];
359→                foreach ($config as $subConfig) {
360→                    $typeIds = Arr::get($subConfig, 'type_ids', []);
361→                    $payCompanyIds = Arr::get($subConfig, 'pay_company_ids', []);
362→                    if (in_array($context['stamp_type'], $typeIds) && in_array($context['pay_company'], $payCompanyIds)) {
363→                        // 命中了，使用命中的自定义规则
364→                        $subIds = array_merge($subIds, $subConfig['ids']);
365→                        $subNicknames = array_merge($subNicknames, $subConfig['nicknames']);
366→                    }
367→                }
368→                if (!empty($subIds)) {
369→                    $ids = $subIds;
370→                    $nicknames = $subNicknames;
371→                }
372→            }
373→        }
374→
375→        // 如果 ids 为空
376→        if (empty($ids)) {
377→            if ($skip) {
378→                return ['ids' => [], 'nicknames' => []];
379→            }
380→            throw new WorkflowException("Special stakeholder type {$type} Not Found");
381→        }
382→
383→        return ['ids' => $ids, 'nicknames' => $nicknames];
384→    }
