175→                    // 美术
176→                    $departments = Arr::only(CommonConst::PAY_STAMP_DEPARTMENT, CommonConst::THIRD_SUPERVISOR_DEPARTMENTS);
177→                    if (in_array($context['department'], $departments)) {
178→                        return 1;
179→                    }
180→                    return 0;
181→                },
182→            ],
183→            self::FINANCIAL_PAYMENT_PENDING => [
184→                Action::APPROVE => function (array $context, string $processKey): int {
185→                    $payType = Arr::get($context, 'pay_type');
186→                    if ($payType == AdvanceChargeDetail::PREPAYMENT) {
187→                        return 0;
188→                    }
189→                    if ($payType == AdvanceChargeDetail::TELEGRAPHIC) {
190→                        return 1;
191→                    }
192→                    return -1;
193→                },
194→            ],
195→        ];
