221→    /**
222→     * 获取特殊花名.
223→     *
224→     * @param string $connection
225→     * @param string $type
226→     * @param array $context
227→     * @return array
228→     */
229→    public function fetchSpecialSfuser(string $connection, string $type, array $context): array
230→    {
231→        // 只有运营, 美术, 市场会有第二第三个部门主管
232→        $departments2 = Arr::only(CommonConst::PAY_STAMP_DEPARTMENT, CommonConst::SECOND_SUPERVISOR_DEPARTMENTS);
233→        $departments3 = Arr::only(CommonConst::PAY_STAMP_DEPARTMENT, CommonConst::THIRD_SUPERVISOR_DEPARTMENTS);
234→        $skip = false;
235→        if ($type == CommonSpecialStakeholder::SECOND_SUPERVISOR_TYPE && !in_array($context['department'], $departments2)
236→            || $type == CommonSpecialStakeholder::THIRD_SUPERVISOR_TYPE && !in_array($context['department'], $departments3)) {
237→            $skip = true;
238→        }
239→
240→        $stakeholders = Stakeholder::getData($connection, $type);
241→        if (empty($stakeholders)) {
242→            if ($skip) {
243→                return ['ids' => [], 'nicknames' => []];
244→            }
245→            throw new WorkflowException("Special stakeholder type {$type} Not Found");
246→        }
247→
248→        // 默认采用外面的 ids
249→        $ids = Arr::get($stakeholders, 'ids', []);
250→        $nicknames = Arr::get($stakeholders, 'nicknames', []);
251→        $config = Arr::get($stakeholders, 'special_config', []);
252→
253→        if ($config) {
254→            // 存在特殊配置
255→            if (in_array($type, CommonSpecialStakeholder::SUPERVISOR_TYPES)) {
256→                foreach ($config as $subConfig) {
257→                    $departmentId = Arr::get($subConfig, 'department_id', 0);
258→                    if ($context['department'] == $departmentId) {
259→                        // 命中了，使用命中的自定义规则
260→                        $ids = $subConfig['ids'];
261→                        $nicknames = $subConfig['nicknames'];
262→                        break; // 使用第一个
263→                    }
264→                }
265→            } elseif (in_array($type, [CommonSpecialStakeholder::FINANCIAL_HANDEL_TYPE, CommonSpecialStakeholder::FINANCIAL_PAYMENT_TYPE])) {
266→                $subIds = [];
267→                $subNicknames = [];
268→                foreach ($config as $subConfig) {
269→                    $payCompanyIds = Arr::get($subConfig, 'pay_company_ids', []);
270→                    if (in_array($context['pay_company'], $payCompanyIds)) {
271→                        // 命中了，使用命中的自定义规则
272→                        $subIds = array_merge($subIds, $subConfig['ids']);
273→                        $subNicknames = array_merge($subNicknames, $subConfig['nicknames']);
274→                    }
275→                }
276→                if (!empty($subIds)) {
277→                    $ids = $subIds;
278→                    $nicknames = $subNicknames;
279→                }
280→            } elseif ($type == CommonSpecialStakeholder::FINANCIAL_TYPE) {
281→                foreach ($config as $subConfig) {
282→                    $payCompanyIds = Arr::get($subConfig, 'pay_company_ids', []);
283→                    if (in_array($context['pay_company'], $payCompanyIds)) {
284→                        $ids = $subConfig['ids'];
285→                        $nicknames = $subConfig['nicknames'];
286→                        break; // 使用第一个
287→                    }
288→                }
289→            }
290→        }
291→
292→        // 如果 ids 为空
293→        if (empty($ids)) {
294→            if ($skip) {
295→                return ['ids' => [], 'nicknames' => []];
296→            }
297→            throw new WorkflowException("Special stakeholder type {$type} Not Found");
298→        }
299→
300→        return ['ids' => $ids, 'nicknames' => $nicknames];
301→    }
