199→        $departments = ReimbursementCostSubject::where('parent_id', 0)->whereIn('type', [0, 1])
200→            ->select('id', 'name', 'is_closed')->get()->toArray();
201→        $branches = ReimbursementCostSubject::where('parent_id', '<>', 0)->whereIn('type', [0, 1])
202→            ->select('id', 'name', 'parent_id', 'is_closed')
203→            ->get()->groupBy('parent_id')->toArray();
204→
205→        foreach ($departments as &$one) {
206→            if (array_key_exists($one['id'], $branches)) {
207→                $one['children'] = array_map(function ($one) {
208→                    return Arr::only($one, ['id', 'name', 'is_closed']);
209→                }, $branches[$one['id']]);
210→            } else {
211→                $one['children'] = [];
212→            }
213→        }
214→        unset($one);
215→
216→        return $departments;
217→    }
